def get_parameters(
        self, handler: Any
    ) -> Optional[List[Union[Parameter, Reference]]]:
    if not hasattr(handler, "binders"):
        return None
    binders: List[Binder] = handler.binders

    docs = self.get_handler_docs(handler)
    parameters_info = (docs.parameters if docs else None) or {}

    # Refactored first loop using dictionary comprehension
    parameters = {
        binder.parameter_name: Parameter(
            name=binder.parameter_name,
            in_=self.get_parameter_location_for_binder(binder),
            required=(
                True if self.get_parameter_location_for_binder(binder) == ParameterLocation.PATH
                else binder.required and binder.default is empty
            ),
            schema=self.get_schema_by_type(binder.expected_type),
            description=parameters_info.get(binder.parameter_name, {}).description or "",
            example=parameters_info.get(binder.parameter_name, {}).example or None,
        )
        for binder in binders
        if self.get_parameter_location_for_binder(binder) is not None
    }

    # Refactored second loop using dictionary comprehension
    extra_parameters = {
        key: Parameter(
            name=key,
            in_=self._parameter_source_to_openapi_obj(
                param_info.source or ParameterSource.QUERY
            ),
            required=param_info.required,
            schema=self.get_schema_by_type(param_info.value_type) if param_info.value_type else None,
            description=param_info.description,
            example=param_info.example,
        )
        for key, param_info in parameters_info.items() if key not in parameters
    }

    parameters.update(extra_parameters)

    return list(parameters.values())

def _GetXcodeEnv(
    xcode_settings, built_products_dir, srcroot, configuration, additional_settings=None
):
    """Return the environment variables that Xcode would set. See
  http://developer.apple.com/library/mac/#documentation/DeveloperTools/Reference/XcodeBuildSettingRef/1-Build_Setting_Reference/build_setting_ref.html#//apple_ref/doc/uid/TP40003931-CH3-SW153
  for a full list.

  Args:
      xcode_settings: An XcodeSettings object. If this is None, this function
          returns an empty dict.
      built_products_dir: Absolute path to the built products dir.
      srcroot: Absolute path to the source root.
      configuration: The build configuration name.
      additional_settings: An optional dict with more values to add to the
          result.
  """

    if not xcode_settings:
        return {}

    # This function is considered a friend of XcodeSettings, so let it reach into
    # its implementation details.
    spec = xcode_settings.spec

    # These are filled in on an as-needed basis.
    env = {
        "BUILT_FRAMEWORKS_DIR": built_products_dir,
        "BUILT_PRODUCTS_DIR": built_products_dir,
        "CONFIGURATION": configuration,
        "PRODUCT_NAME": xcode_settings.GetProductName(),
        "SRCROOT": srcroot,
        "SOURCE_ROOT": "${SRCROOT}",
        "TARGET_BUILD_DIR": built_products_dir,
        "TEMP_DIR": "${TMPDIR}",
        "XCODE_VERSION_ACTUAL": XcodeVersion()[0],
    }

    if xcode_settings.GetPerConfigSetting("SDKROOT", configuration):
        env["SDKROOT"] = xcode_settings._SdkPath(configuration)
    else:
        env["SDKROOT"] = ""

    if xcode_settings.mac_toolchain_dir:
        env["DEVELOPER_DIR"] = xcode_settings.mac_toolchain_dir

    if spec["type"] in (
        "executable",
        "static_library",
        "shared_library",
        "loadable_module",
    ):
        env["EXECUTABLE_NAME"] = xcode_settings.GetExecutableName()
        env["EXECUTABLE_PATH"] = xcode_settings.GetExecutablePath()
        env["FULL_PRODUCT_NAME"] = xcode_settings.GetFullProductName()
        mach_o_type = xcode_settings.GetMachOType()
        if mach_o_type:
            env["MACH_O_TYPE"] = mach_o_type
        env["PRODUCT_TYPE"] = xcode_settings.GetProductType()

    if xcode_settings._IsBundle():
        env.update({
            "BUILT_FRAMEWORKS_DIR": os.path.join(
                built_products_dir + os.sep + xcode_settings.GetBundleFrameworksFolderPath()
            ),
            "CONTENTS_FOLDER_PATH": xcode_settings.GetBundleContentsFolderPath(),
            "EXECUTABLE_FOLDER_PATH": xcode_settings.GetBundleExecutableFolderPath(),
            "UNLOCALIZED_RESOURCES_FOLDER_PATH": xcode_settings.GetBundleResourceFolder(),
            "JAVA_FOLDER_PATH": xcode_settings.GetBundleJavaFolderPath(),
            "FRAMEWORKS_FOLDER_PATH": xcode_settings.GetBundleFrameworksFolderPath(),
            "SHARED_FRAMEWORKS_FOLDER_PATH": xcode_settings.GetBundleSharedFrameworksFolderPath(),
            "SHARED_SUPPORT_FOLDER_PATH": xcode_settings.GetBundleSharedSupportFolderPath(),
            "PLUGINS_FOLDER_PATH": xcode_settings.GetBundlePlugInsFolderPath(),
            "XPCSERVICES_FOLDER_PATH": xcode_settings.GetBundleXPCServicesFolderPath(),
            "INFOPLIST_PATH": xcode_settings.GetBundlePlistPath(),
            "WRAPPER_NAME": xcode_settings.GetWrapperName(),
        })

    install_name = xcode_settings.GetInstallName()
    if install_name:
        env["LD_DYLIB_INSTALL_NAME"] = install_name
    install_name_base = xcode_settings.GetInstallNameBase()
    if install_name_base:
        env["DYLIB_INSTALL_NAME_BASE"] = install_name_base

    xcode_version, _ = XcodeVersion()
    if xcode_version >= "0500" and not env.get("SDKROOT"):
        sdk_root = xcode_settings._SdkRoot(configuration)
        if not sdk_root:
            sdk_root = xcode_settings._XcodeSdkPath("")
        if sdk_root is None:
            sdk_root = ""
        env["SDKROOT"] = sdk_root

    if not additional_settings:
        additional_settings = {}
    else:
        # Flatten lists to strings using dictionary comprehension.
        additional_settings = {
            k: " ".join(v) if not isinstance(v, str) else v
            for k, v in additional_settings.items()
        }

    # Normalize environment variable references using dictionary comprehension.
    additional_settings = {
        k: _NormalizeEnvVarReferences(v)
        for k, v in {**env, **additional_settings}.items()
    }

    return additional_settings

