def infinite_cycles(self):
    # Using dictionary comprehension to initialize 'terminates' for Terminals.
    terminates = {t: True for t in self.Terminals}

    terminates['$end'] = True

    # Using dictionary comprehension to initialize 'terminates' for Nonterminals to False.
    terminates.update({n: False for n in self.Nonterminals})

    # Then propagate termination until no change:
    while True:
        some_change = False
        for n, pl in self.Prodnames.items():
            # Nonterminal n terminates iff any of its productions terminates.
            for p in pl:
                # Production p terminates iff all of its rhs symbols terminate.
                for s in p.prod:
                    if not terminates[s]:
                        # The symbol s does not terminate,
                        # so production p does not terminate.
                        p_terminates = False
                        break
                else:
                    # didn't break from the loop,
                    # so every symbol s terminates
                    # so production p terminates.
                    p_terminates = True

                if p_terminates:
                    # symbol n terminates!
                    if not terminates[n]:
                        terminates[n] = True
                        some_change = True
                    # Don't need to consider any more productions for this n.
                    break

        if not some_change:
            break

    # Using list comprehension to filter the infinite cycles.
    infinite = [
        s for s, term in terminates.items()
        if not term and (s in self.Prodnames or s in self.Terminals or s == 'error')
    ]

    return infinite

