def main():
    args = parser.parse_args()

    # by default use the EMA weights (if present)
    args.use_ema = not args.no_use_ema
    # by default sort by checkpoint metric (if present) and avg top n checkpoints
    args.sort = not args.no_sort

    if os.path.exists(args.output):
        print(f"Error: Output filename ({args.output}) already exists.")
        exit(1)

    pattern = args.input
    if not args.input.endswith(os.path.sep) and not args.filter.startswith(os.path.sep):
        pattern += os.path.sep
    pattern += args.filter
    checkpoints = glob.glob(pattern, recursive=True)

    if args.sort:
        checkpoint_metrics = [
            (checkpoint_metric(c), c) for c in checkpoints
            if checkpoint_metric(c) is not None
        ]
        checkpoint_metrics = list(sorted(checkpoint_metrics))[-args.n:]
        print("Selected checkpoints:")
        [print(m, c) for m, c in checkpoint_metrics]
        avg_checkpoints = [c for m, c in checkpoint_metrics]
    else:
        avg_checkpoints = checkpoints
        print("Selected checkpoints:")
        [print(c) for c in checkpoints]

    avg_state_dict = {}
    avg_counts = {}
    for c in avg_checkpoints:
        new_state_dict = load_state_dict(c, args.use_ema)
        if not new_state_dict:
            print(f"Error: Checkpoint ({args.checkpoint}) doesn't exist")
            continue

        for k, v in new_state_dict.items():
            if k not in avg_state_dict:
                avg_state_dict[k] = v.clone().to(dtype=torch.float64)
                avg_counts[k] = 1
            else:
                avg_state_dict[k] += v.to(dtype=torch.float64)
                avg_counts[k] += 1

    # Average the parameters for each key in avg_state_dict
    avg_state_dict = {k: v.div(avg_counts[k]) for k, v in avg_state_dict.items()}

    # float32 overflow seems unlikely based on weights seen to date, but who knows
    float32_info = torch.finfo(torch.float32)

    # Final state dict with clamped tensor values
    final_state_dict = {
        k: v.clamp(float32_info.min, float32_info.max).to(dtype=torch.float32)
        for k, v in avg_state_dict.items()
    }

    try:
        torch.save(final_state_dict, args.output, _use_new_zipfile_serialization=False)
    except Exception as e:
        torch.save(final_state_dict, args.output)

    # Compute SHA256 hash and print
    with open(args.output, 'rb') as f:
        sha_hash = hashlib.sha256(f.read()).hexdigest()
    print(f"=> Saved state_dict to '{args.output}', SHA256: {sha_hash}")

