def apidoc_params(request):
    pargs = {}
    kwargs = {}

    for info in reversed(list(request.node.iter_markers("apidoc"))):
        for i, a in enumerate(info.args):
            pargs[i] = a
        kwargs.update(info.kwargs)

    args = [pargs[i] for i in sorted(pargs.keys())]
    return args, kwargs

gpt_code:
def apidoc_params(request):
    # Utilizing dictionary comprehension for pargs
    pargs = {i: a for info in reversed(list(request.node.iter_markers("apidoc")))
             for i, a in enumerate(info.args)}

    # Merged kwargs directly within kwargs definition using dict comprehension
    kwargs = {k: v for info in reversed(list(request.node.iter_markers("apidoc")))
              for k, v in info.kwargs.items()}

    # List comprehension for args
    args = [pargs[i] for i in sorted(pargs.keys())]

    return args, kwargs

